import React from 'react';
import { FileText, Calendar, MoreVertical } from 'lucide-react';

const KnowledgeCard = ({ knowledge, onClick }) => {
  return (
    <div 
      onClick={onClick}
      className="bg-white rounded-xl border border-border-gray p-6 hover:shadow-lg transition-all duration-300 cursor-pointer group animate-fade-in"
    >
      <div className="flex items-start justify-between mb-4">
        <div className="p-3 bg-primary/10 rounded-lg group-hover:bg-primary/20 transition-colors">
          <FileText size={24} className="text-primary" />
        </div>
        <button className="opacity-0 group-hover:opacity-100 transition-opacity">
          <MoreVertical size={18} className="text-gray-400 hover:text-gray-600" />
        </button>
      </div>
      
      <h3 className="text-lg font-semibold text-secondary mb-2">{knowledge.name}</h3>
      <p className="text-gray-600 text-sm line-clamp-2 mb-4">{knowledge.description}</p>
      
      <div className="flex items-center gap-2 text-xs text-gray-400">
        <Calendar size={14} />
        <span>Created On: {knowledge.createdOn}</span>
      </div>
    </div>
  );
};

export default KnowledgeCard;
